        private static string MaskEmail(string email)
        {
            if (string.IsNullOrEmpty(email)) return "[empty]";
            var parts = email.Split('@');
            if (parts.Length != 2) return "[invalid]";
            var localPart = parts[0];
            var masked = localPart.Length <= 2
                ? "**"
                : localPart[0] + new string('*', localPart.Length - 2) + localPart[^1];
            return $"{masked}@{parts[1]}";
        }

        private static string GetLast4(string cardNumber)
        {
            if (string.IsNullOrEmpty(cardNumber) || cardNumber.Length < 4) return "****";
            return cardNumber[^4..];
